#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelMinGptNewGeluCustom {
public:
    __aicore__ inline KernelMinGptNewGeluCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 3, tileLen_ * sizeof(float)); // for x^3, inner, tanh_input
        pipe_.InitBuffer(tanhTmpBuf_, tileLen_ * sizeof(float) / 2); // shared tmp for Tanh
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Grid-stride loop
        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        uint32_t curLen = totalLen_ - base;
        if (curLen > tileLen_) curLen = tileLen_;
        CopyIn(base, curLen);

        while (true) {
            const uint32_t nextBase = base + strideElems;
            uint32_t nextLen = 0;
            if (nextBase < totalLen_) {
                nextLen = totalLen_ - nextBase;
                if (nextLen > tileLen_) nextLen = tileLen_;
                CopyIn(nextBase, nextLen);
            }

            Compute(curLen);
            CopyOut(base, curLen);

            if (nextLen == 0) break;
            base = nextBase;
            curLen = nextLen;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

        AscendC::LocalTensor<float> tmp0 = tmpQueue_.AllocTensor<float>();  // x^3
        AscendC::LocalTensor<float> tmp1 = tmpQueue_.AllocTensor<float>();  // inner
        AscendC::LocalTensor<float> tmp2 = tmpQueue_.AllocTensor<float>();  // tanh_input

        // Constants
        const float const1 = 0.7978845608028654f;  // sqrt(2/pi)
        const float const2 = 0.044715f;
        const float const3 = 0.5f;

        // Compute x^3
        AscendC::Mul(tmp0, xLocal, xLocal, len);   // tmp0 = x^2
        AscendC::Mul(tmp0, tmp0, xLocal, len);     // tmp0 = x^3

        // inner = x + const2 * x^3
        AscendC::Muls(tmp1, tmp0, const2, len);    // tmp1 = const2 * x^3
        AscendC::Add(tmp1, xLocal, tmp1, len);     // tmp1 = x + const2*x^3

        // tanh_input = const1 * inner
        AscendC::Muls(tmp2, tmp1, const1, len);    // tmp2 = const1 * inner

        // tanh_result = tanh(tanh_input)  // in-place tmp2
        // Use shared tmp buffer for Tanh
        AscendC::LocalTensor<uint8_t> sharedBuf = tanhTmpBuf_.Get<uint8_t>();
        AscendC::Tanh(tmp2, tmp2, sharedBuf, len); // tmp2 = tanh(tanh_input)

        // y = const3 * x * (1.0 + tanh)
        AscendC::Adds(tmp2, tmp2, 1.0f, len);      // tmp2 = 1 + tanh  (fixed: use Adds instead of Add)
        AscendC::Mul(tmp1, xLocal, tmp2, len);     // tmp1 = x * (1+tanh)
        AscendC::Muls(yLocal, tmp1, const3, len);  // y = const3 * tmp1

        tmpQueue_.FreeTensor(tmp0);
        tmpQueue_.FreeTensor(tmp1);
        tmpQueue_.FreeTensor(tmp2);
        outQueueY_.EnQue<float>(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 3> tmpQueue_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> tanhTmpBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void min_gpt_new_gelu_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
